import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../App';
import api from '../api';

const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

export default function Register() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [form, setForm] = useState({ name: '', email: '', password: '', confirm: '', age: '', bloodGroup: '', allergies: '', chronicConditions: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const set = k => e => setForm({ ...form, [k]: e.target.value });

  const nextStep = e => {
    e.preventDefault();
    if (form.password.length < 6) { setError('Password must be at least 6 characters'); return; }
    if (form.password !== form.confirm) { setError('Passwords do not match'); return; }
    setError(''); setStep(2);
  };

  const handleSubmit = async e => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      const res = await api.post('/api/register', form);
      login(res.data.user, res.data.token);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Registration failed. Please try again.');
      setStep(1);
    } finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight: 'calc(100vh - 64px)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem 1.25rem', background: 'linear-gradient(135deg, #f0fdf4 0%, #dcfce7 100%)' }}>
      <div className="card fade-up" style={{ width: '100%', maxWidth: 440 }}>
        <div style={{ textAlign: 'center', marginBottom: '1.5rem' }}>
          <div style={{ display: 'flex', justifyContent: 'center', gap: 8, marginBottom: 16 }}>
            {[1, 2].map(s => (
              <div key={s} style={{ width: 32, height: 4, borderRadius: 2, background: s <= step ? '#16a34a' : '#e5e7eb', transition: 'background 0.3s' }} />
            ))}
          </div>
          <h2 style={{ fontSize: '1.6rem', marginBottom: 4 }}>{step === 1 ? 'Create Account' : 'Health Profile'}</h2>
          <p style={{ color: '#6b7280', fontSize: '0.875rem' }}>
            {step === 1 ? 'Join MediHelp for personalized nutrition guidance' : 'Optional — helps improve your AI recommendations'}
          </p>
        </div>

        {error && <div className="alert alert-error">{error}</div>}

        {step === 1 ? (
          <form onSubmit={nextStep}>
            <div className="form-group">
              <label className="form-label">Full Name</label>
              <input className="form-input" value={form.name} onChange={set('name')} placeholder="e.g. Wanjiku Kamau" required />
            </div>
            <div className="form-group">
              <label className="form-label">Email Address</label>
              <input type="email" className="form-input" value={form.email} onChange={set('email')} placeholder="you@email.com" required />
            </div>
            <div className="form-group">
              <label className="form-label">Password</label>
              <input type="password" className="form-input" value={form.password} onChange={set('password')} placeholder="Min. 6 characters" required />
            </div>
            <div className="form-group">
              <label className="form-label">Confirm Password</label>
              <input type="password" className="form-input" value={form.confirm} onChange={set('confirm')} placeholder="Repeat password" required />
            </div>
            <button type="submit" className="btn btn-primary" style={{ width: '100%', justifyContent: 'center', padding: '0.75rem', marginTop: 8 }}>
              Continue →
            </button>
          </form>
        ) : (
          <form onSubmit={handleSubmit}>
            <div className="grid-2">
              <div className="form-group">
                <label className="form-label">Age</label>
                <input type="number" className="form-input" value={form.age} onChange={set('age')} placeholder="e.g. 28" min="1" max="120" />
              </div>
              <div className="form-group">
                <label className="form-label">Blood Group</label>
                <select className="form-input" value={form.bloodGroup} onChange={set('bloodGroup')}>
                  <option value="">Unknown</option>
                  {BLOOD_GROUPS.map(b => <option key={b}>{b}</option>)}
                </select>
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">Known Allergies</label>
              <input className="form-input" value={form.allergies} onChange={set('allergies')} placeholder="e.g. peanuts, shellfish (or leave blank)" />
            </div>
            <div className="form-group">
              <label className="form-label">Chronic Conditions</label>
              <input className="form-input" value={form.chronicConditions} onChange={set('chronicConditions')} placeholder="e.g. diabetes, hypertension (or leave blank)" />
            </div>
            <div style={{ display: 'flex', gap: 8, marginTop: 8 }}>
              <button type="button" className="btn btn-ghost" onClick={() => setStep(1)} style={{ flex: 1, justifyContent: 'center' }}>← Back</button>
              <button type="submit" className="btn btn-primary" disabled={loading} style={{ flex: 2, justifyContent: 'center', padding: '0.75rem' }}>
                {loading ? <><span className="spinner" style={{ width: 16, height: 16 }} /> Creating...</> : 'Create Account'}
              </button>
            </div>
            <button type="button" onClick={handleSubmit} disabled={loading} style={{ width: '100%', background: 'none', border: 'none', color: '#6b7280', cursor: 'pointer', fontSize: '0.8rem', marginTop: 8 }}>
              Skip health profile for now
            </button>
          </form>
        )}

        <p style={{ textAlign: 'center', marginTop: '1.25rem', fontSize: '0.875rem', color: '#6b7280' }}>
          Have an account? <Link to="/login" style={{ color: '#16a34a', fontWeight: 600 }}>Sign in</Link>
        </p>
      </div>
    </div>
  );
}
